.mrg-container {
  --mrg-container-gutter: var(--mrg-semantic-space-inline-lg);
  --mrg-container-max-inline-size: var(--mrg-semantic-container-content);
  box-sizing: border-box;
  inline-size: 100%;
  margin-inline: auto;
  max-inline-size: var(--mrg-container-max-inline-size);
  min-inline-size: 0;
  padding-inline: var(--mrg-container-gutter);
}

.mrg-container[data-width="prose"] {
  --mrg-container-max-inline-size: var(--mrg-semantic-container-prose);
}

.mrg-container[data-width="wide"] {
  --mrg-container-max-inline-size: var(--mrg-semantic-container-wide);
}

.mrg-container[data-width="full"] {
  --mrg-container-max-inline-size: none;
}

.mrg-container[data-gutter="none"] {
  --mrg-container-gutter: 0px;
}

.mrg-container[data-gutter="compact"] {
  --mrg-container-gutter: var(--mrg-semantic-space-inline-sm);
}

.mrg-container[data-gutter="spacious"] {
  --mrg-container-gutter: var(--mrg-semantic-density-panel-padding);
}

.mrg-container[data-safe-area="true"] {
  padding-inline-end: max(var(--mrg-container-gutter), env(safe-area-inset-right));
  padding-inline-start: max(var(--mrg-container-gutter), env(safe-area-inset-left));
}

.mrg-container[data-safe-area="true"]:dir(rtl) {
  padding-inline-end: max(var(--mrg-container-gutter), env(safe-area-inset-left));
  padding-inline-start: max(var(--mrg-container-gutter), env(safe-area-inset-right));
}

.mrg-container[data-query-container="true"] {
  container-type: inline-size;
}

import { forwardRef, type HTMLAttributes } from "react";

import "./container.css";

export type ContainerWidth = "prose" | "content" | "wide" | "full";
export type ContainerGutter = "none" | "compact" | "default" | "spacious";

export interface ContainerProps extends HTMLAttributes<HTMLDivElement> {
  /** Selects a semantic maximum width without accepting arbitrary layout strings. */
  readonly width?: ContainerWidth;
  /** Controls logical inline padding using the public spacing tokens. */
  readonly gutter?: ContainerGutter;
  /** Adds physical safe-area insets to the corresponding logical edge. */
  readonly safeArea?: boolean;
  /** Makes this element an anonymous inline-size query container. */
  readonly queryContainer?: boolean;
}

function joinContainerClassName(className: string | undefined): string {
  return className === undefined || className.trim().length === 0
    ? "mrg-container"
    : `mrg-container ${className}`;
}

export const Container = forwardRef<HTMLDivElement, ContainerProps>(function Container(
  {
    className,
    gutter = "default",
    queryContainer = false,
    safeArea = true,
    width = "content",
    ...nativeProps
  },
  forwardedRef,
) {
  return (
    <div
      {...nativeProps}
      ref={forwardedRef}
      className={joinContainerClassName(className)}
      data-gutter={gutter}
      data-query-container={queryContainer ? "true" : undefined}
      data-safe-area={safeArea ? "true" : "false"}
      data-slot="container"
      data-width={width}
    />
  );
});

Container.displayName = "Container";
